// ========================================
// ДВОЙНАЯ ЗАГРУЗКА КОНТЕКСТА
// ========================================

const taskFromDB = $('2. Load Task').first()?.json;
const inputFromQualifizer = $('1. When Executed by Another Workflow').first()?.json;

// ========================================
// ВАЛИДАЦИЯ
// ========================================

if (!taskFromDB || !taskFromDB.id) {
  throw new Error('Task data from database is missing or invalid');
}

if (!inputFromQualifizer) {
  console.warn('⚠️ WARNING: No input from Qualifizer! Using database data only.');
}

// ========================================
// ОБЪЕДИНЕНИЕ ДАННЫХ
// ========================================

const task = {
  ...taskFromDB,
  effective_user_request: inputFromQualifizer?.effective_user_request || taskFromDB.effective_user_request
};

console.log('📥 Context loaded:', {
  from_db: !!taskFromDB,
  from_qualifizer: !!inputFromQualifizer,
  has_effective_request: !!task.effective_user_request
});

// ========================================
// ИЗВЛЕЧЕНИЕ КОНТЕКСТА
// ========================================

const sourceData = task.source_data || null;
const agentOutput = task.agent_output || { current_version: 0, versions: [] };
const versions = agentOutput.versions || [];
const isUpdate = versions.length > 0;
const currentVersion = agentOutput.current_version || 0;

// ✅ НОВОЕ: Извлекаем текст предыдущей версии
let previousVersionText = null;
if (isUpdate && versions.length > 0) {
  const lastVersion = versions[versions.length - 1];
  previousVersionText = lastVersion.agent_response || null;

  console.log('📝 Task Update Mode:', {
    current_version: currentVersion,
    total_versions: versions.length,
    has_previous_text: !!previousVersionText,
    previous_text_length: previousVersionText ? previousVersionText.length : 0
  });
}

// ========================================
// ВЫБОР ЗАПРОСА ПОЛЬЗОВАТЕЛЯ
// ========================================

const userRequest = task.effective_user_request || task.initial_prompt || 'No user request provided';

console.log('✅ User request selected:', {
  source: task.effective_user_request ? 'Qualifizer' : 'Database',
  length: userRequest.length
});

// ========================================
// ВОЗВРАТ РЕЗУЛЬТАТА
// ========================================

return {
  json: {
    task_id: task.id,
    chat_id: task.chat_id,
    user_id: task.user_id,
    user_request: userRequest,
    source_data: sourceData,
    is_update: isUpdate,
    current_version: currentVersion,
    versions: versions,
    previous_version_text: previousVersionText,  // ✅ НОВОЕ
    text: userRequest
  }
};

