// ========================================
// ПОЛУЧАЕМ ДАННЫЕ
// ========================================

const aiResponse = $input.first().json;
const context = $('4. Prepare Context').first().json;

// ✅ С Structured Output Parser - ВСЕГДА структура {output: {...}}
const parsed = aiResponse.output;

if (!parsed || !parsed.post_text) {
  throw new Error('Output Parser не вернул корректный JSON. Проверьте настройку Structured Output Parser.');
}

console.log('✅ Received parsed output:', {
  has_post_text: !!parsed.post_text,
  post_length: parsed.post_text?.length,
  sources_count: parsed.sources?.length || 0
});

// ========================================
// ВАЛИДАЦИЯ БИЗНЕС-ЛОГИКИ
// ========================================

const postText = parsed.post_text;
const sources = parsed.sources || [];
const changesMade = parsed.changes_made || null;

// Проверка 1: Текст не пустой
if (!postText || postText.trim() === '') {
  throw new Error('Пост пустой! AI не вернул текст в поле post_text.');
}

// Проверка 2: Минимальная длина
if (postText.length < 50) {
  throw new Error(`Пост слишком короткий: ${postText.length} символов (минимум 50)`);
}

// Проверка 3: Если update — желательно описание изменений
if (context.is_update && !changesMade) {
  console.warn('⚠️ WARNING: Update mode but no changes_made provided');
}

console.log('✅ Validation passed:', {
  post_length: postText.length,
  sources_count: sources.length,
  has_changes: !!changesMade
});

// ========================================
// СОЗДАНИЕ НОВОЙ ВЕРСИИ
// ========================================

const newVersion = {
  version: context.current_version + 1,
  user_request: context.user_request,
  agent_response: postText,
  sources: sources,
  metadata: {
    character_count: postText.length,
    estimated_reading_time: Math.ceil(postText.length / 1000) + ' мин'
  },
  changes: changesMade || (context.is_update ? 'Обновлён по запросу пользователя' : null),
  message_id: null,  // ✅ Заполнится после отправки в Telegram
  timestamp: new Date().toISOString()
};

// Формируем обновлённый agent_output
const updatedAgentOutput = {
  current_version: newVersion.version,
  versions: [
    ...context.versions,
    newVersion
  ]
};

console.log('✅ New version created:', {
  version: newVersion.version,
  has_changes: !!newVersion.changes,
  sources_count: sources.length
});

// ========================================
// ВОЗВРАТ РЕЗУЛЬТАТА
// ========================================

return {
  json: {
    task_id: context.task_id,
    chat_id: context.chat_id,
    user_id: context.user_id,
    post_text: postText,              // ← В Telegram попадёт ТОЛЬКО ЭТО
    sources: sources,
    metadata: newVersion.metadata,
    new_version: newVersion,
    updated_agent_output: updatedAgentOutput
  }
};

// ========================================
// ОБНОВЛЕНИЕ TASK В БД (С MESSAGE_ID)
// ========================================

// Получаем данные от Validate Output
const validateOutput = $('7. Validate Output').first().json;

// Получаем message_id от Send to Telegram
const telegramResponse = $('8. Send to Telegram').first().json;
const messageId = telegramResponse.result?.message_id;

console.log('📥 Update Task inputs:', {
  has_validate_output: !!validateOutput,
  has_telegram_response: !!telegramResponse,
  message_id: messageId
});

// Обновляем последнюю версию с message_id
const updatedAgentOutput = validateOutput.updated_agent_output;

if (messageId) {
  const lastVersionIndex = updatedAgentOutput.versions.length - 1;
  updatedAgentOutput.versions[lastVersionIndex].message_id = messageId;

  console.log('✅ Updated version with message_id:', {
    version: updatedAgentOutput.versions[lastVersionIndex].version,
    message_id: messageId
  });
} else {
  console.warn('⚠️ WARNING: message_id not found in Telegram response!');
}

// Возвращаем данные для Supabase UPDATE
return {
  json: {
    task_id: validateOutput.task_id,
    agent_output: updatedAgentOutput,
    status: 'completed',
    updated_at: new Date().toISOString()
  }
};
